import { adjustColorBrightness } from './utils';

export const drawThreadPattern = (
  ctx: CanvasRenderingContext2D,
  x: number,
  y: number,
  width: number,
  height: number,
  baseColor: string
): void => {
  const darkerColor = adjustColorBrightness(baseColor, -40);

  // Fine vertical threads
  for (let i = 0; i < width; i += 1.5) {
    ctx.globalAlpha = 0.6;
    ctx.strokeStyle = darkerColor;
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(x + i, y);
    ctx.lineTo(x + i, y + height);
    ctx.stroke();
  }

  // Thicker vertical threads (every 6px)
  for (let i = 0; i < width; i += 6) {
    ctx.globalAlpha = 0.8;
    ctx.strokeStyle = darkerColor;
    ctx.lineWidth = 1.5;
    ctx.beginPath();
    ctx.moveTo(x + i, y);
    ctx.lineTo(x + i, y + height);
    ctx.stroke();
  }

  ctx.globalAlpha = 1.0;
};

export const renderBeltCanvas = (
  canvas: HTMLCanvasElement | null,
  gridData: string[][],
  leatherColorName: string
): void => {
  if (!canvas) return;
  const ctx = canvas.getContext('2d', { alpha: true });
  if (!ctx) return;

  const rows = gridData.length;
  const cols = gridData[0]?.length || 64;
  // Snap all tile edges to integer pixels to avoid hairline seams
  // when the canvas is scaled in CSS.
  const colEdges = Array.from({ length: cols + 1 }, (_, i) =>
    Math.round((i * canvas.width) / cols)
  );
  const rowEdges = Array.from({ length: rows + 1 }, (_, i) =>
    Math.round((i * canvas.height) / rows)
  );

  const leatherColourMap: Record<string, string> = {
    Brown: '#552B06',
    Black: '#1A1A1A',
    Tan: '#B8906B',
  };

  const leatherColour = leatherColourMap[leatherColorName] || '#552B06';

  ctx.clearRect(0, 0, canvas.width, canvas.height);

  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      let color = gridData[r][c];
      const x = colEdges[c];
      const y = rowEdges[r];
      const cellWidth = colEdges[c + 1] - x;
      const cellHeight = rowEdges[r + 1] - y;

      // Replace leather placeholder with selected leather color
      if (color === '#552B06') {
        color = leatherColour;
      }

      ctx.fillStyle = color;
      ctx.fillRect(x, y, cellWidth, cellHeight);

      // Only draw thread texture on thread areas (not leather)
      if (gridData[r][c] !== '#552B06') {
        drawThreadPattern(ctx, x, y, cellWidth, cellHeight, color);
      }
    }
  }

  // Subtle border (matches original)
  ctx.strokeStyle = '#999999';
  ctx.lineWidth = 1;
  ctx.strokeRect(0, 0, canvas.width, canvas.height);
};

export const canvasToImage = (canvas: HTMLCanvasElement | null): string => {
  return canvas ? canvas.toDataURL('image/png') : '';
};

