// Apply user colors exactly like the original HTML
export const applyColorsToPattern = (
  originalPattern: string[][],
  color1Hex: string | null,
  color2Hex: string | null,
  color3Hex: string | null,
  stripe1Hex: string | null,
  stripe2HexIn?: string | null,
  isClassic4: boolean = false,
  designType?: string
): string[][] => {
  const isStripePattern = stripe1Hex !== null && !isClassic4;
  const is2Stripe = designType === 'classic-2stripe';
  const stripe2Hex = stripe2HexIn ?? null;

  return originalPattern.map((row) =>
    row.map((cell) => {
      if (cell === '#7B030A' && color1Hex) return color1Hex;
      if (cell === '#FFFFFF' && color2Hex) return color2Hex;
      if (cell === '#CCCCCC') {
        if (is2Stripe && stripe1Hex) return stripe1Hex;
        if (isStripePattern && stripe1Hex) return stripe1Hex;
        if (color3Hex) return color3Hex;
      }
      if (cell === '#D0D0D0') {
        if (is2Stripe && stripe2Hex) return stripe2Hex;
        if (color3Hex) return color3Hex;
      }
      if (cell === '#E8E8E8') {
        if (stripe2Hex) return stripe2Hex;
      }
      return cell; // leather stays #552B06
    })
  );
};